  requires EmailWhere(email)
  requires email !in st.user_by_email
  requires |password| >= 8
  requires |display_name| >= 1
  ensures user.id == old(st.next_user_id)
  ensures user.email == email
  ensures user.password_hash == hash(password)
  ensures user.display_name == display_name
  ensures user.is_active == true
  ensures user.last_login == None
  ensures st.next_user_id == old(st.next_user_id) + 1
  ensures st.users == old(st.users)[user.id := user]
  ensures st.user_by_email == old(st.user_by_email)[email := user]
  ensures |st.users| == |old(st.users)| + 1
  ensures ServiceStateInv(st)
  modifies st
{
  // keep ghost copies of the parts of the state we will reason about
  ghost var oldUsers := st.users;
  ghost var oldByEmail := st.user_by_email;
  ghost var oldNext := st.next_user_id;

  // the new user's id is the current next_user_id
  var id := st.next_user_id;
  // from ServiceStateInv(st) we know no existing user equals st.next_user_id
  assert id !in st.users;

  // build the new user
  var newUser := User(id, email, hash(password), display_name, now(), None, true);

  // prepare return value
  user := newUser;

  // update state: add the new user and the user_by_email mapping, increment next_user_id
  st.users := st.users[id := newUser];
  st.user_by_email := st.user_by_email[email := newUser];
  st.next_user_id := id + 1;

  // help the verifier with obvious equalities
  assert st.next_user_id == oldNext + 1;
  assert st.users == oldUsers[oldNext := newUser];
  assert st.user_by_email == oldByEmail[email := newUser];
  assert |st.users| == |oldUsers| + 1;

  // Now prove the ServiceStateInv(st) conjuncts hold after the update.
  // Many of these follow directly from the corresponding facts before the update
  // together with the consistent insertion we performed.

  // 1) distinct emails among users:
