  //    or one is the newly inserted id (email distinct by precondition email !in oldByEmail),
  //    or both equal the new id (then ids equal). The solver can discharge this with the facts above.

  // 2) st.user_by_email consistency:
  //    For existing emails this holds because oldByEmail entries remain unchanged.
  //    For the newly inserted email, we added email := newUser and st.users[id] == newUser.
  assert st.user_by_email[email].id == id;
  assert st.user_by_email[email] == st.users[id];

  // 3) every user id maps back into user_by_email:
  //    For old users this held before; for the new user we have newUser.email == email and we added that mapping.
  assert st.users[id].email == email;
  assert st.user_by_email[st.users[id].email] == st.users[id];

  // 4) sessions-related invariants are unchanged because we didn't modify sessions or next_session_id.

  // 5) ids less than next_user_id:
  //    For old users u we had u < oldNext, and oldNext < oldNext + 1 = st.next_user_id so u < st.next_user_id.
  //    For the new user id == oldNext, and id < id + 1 = st.next_user_id.
  assert forall u :: u in oldUsers ==> u < st.next_user_id;
  assert id < st.next_user_id;

  // 6) session id properties unchanged (we didn't touch sessions or next_session_id).

